import type { RequestHandler } from "@builder.io/qwik-city";
import {
  addSubscriber,
  removeSubscriber,
  getCount,
  frame,
  type Subscriber,
} from "~/server/counter-store";

/**
 * SSE stream endpoint: `GET /api/counter/stream`
 *
 * On connection it immediately emits one frame carrying the current counter
 * value, then keeps the connection open and streams a new frame every time
 * the shared counter changes (broadcast from the mutation endpoint).
 *
 * The subscriber's writer is removed from the registry when the request
 * aborts (client disconnects).
 */
export const onGet: RequestHandler = async (requestEvent) => {
  const { headers, signal, getWritableStream } = requestEvent;

  // SSE response headers.
  headers.set("Content-Type", "text/event-stream; charset=utf-8");
  headers.set("Cache-Control", "no-cache, no-transform");
  headers.set("Connection", "keep-alive");
  headers.set("X-Accel-Buffering", "no");

  const stream = getWritableStream();
  const writer = stream.getWriter();

  const subscriber: Subscriber = {
    send(count: number) {
      // writer.write may throw if the stream is closed/errored.
      writer.write(frame(count));
    },
    close() {
      removeSubscriber(subscriber);
      try {
        writer.close();
      } catch {
        // Already closed.
      }
    },
  };

  // Register so this connection receives all future broadcasts.
  addSubscriber(subscriber);

  // Immediately emit the current counter value to the newly connected client.
  try {
    writer.write(frame(getCount()));
  } catch {
    subscriber.close();
    return;
  }

  // Remove the subscriber when the client disconnects / request aborts.
  signal.addEventListener("abort", () => {
    subscriber.close();
  });

  // Hold the endpoint open until the stream closes. The promise resolves when
  // the writer is closed (e.g. via the abort handler above).
  await new Promise<void>((resolve) => {
    signal.addEventListener("abort", () => resolve(), { once: true });
    writer.closed.then(() => resolve()).catch(() => resolve());
  });
};

import type { RequestHandler } from "@builder.io/qwik-city";
import { getCount, applyDelta } from "~/server/counter-store";

/**
 * Current-value endpoint: `GET /api/counter`
 *
 * Responds with status 200 and JSON body `{ "count": <integer> }` containing
 * the current shared counter value.
 */
export const onGet: RequestHandler = async (requestEvent) => {
  requestEvent.json(200, { count: getCount() });
};

/**
 * Mutation endpoint: `POST /api/counter`
 *
 * Request body: JSON `{ "delta": <integer> }` (delta may be negative).
 * Applies the delta to the shared counter, broadcasts the new value to all
 * connected SSE subscribers, and responds with status 200 and JSON body
 * `{ "count": <integer> }` containing the updated value.
 */
export const onPost: RequestHandler = async (requestEvent) => {
  const body = (await requestEvent.parseBody()) as { delta?: unknown } | null;

  const rawDelta = body?.delta;
  const delta = typeof rawDelta === "number" && Number.isFinite(rawDelta)
    ? Math.trunc(rawDelta)
    : 0;

  const count = applyDelta(delta);

  requestEvent.json(200, { count });
};

import { component$, useSignal, useVisibleTask$ } from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  // Reactive state holding the latest counter value streamed from the server.
  const count = useSignal(0);

  // Browser-only visible task: subscribe to the SSE stream via EventSource.
  useVisibleTask$(async ({ cleanup }) => {
    const eventSource = new EventSource("/api/counter/stream");

    eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data) as { count?: unknown };
        if (typeof data.count === "number" && Number.isFinite(data.count)) {
          count.value = Math.trunc(data.count);
        }
      } catch {
        // Ignore malformed frames.
      }
    };

    // Close the stream connection when the component is destroyed.
    cleanup(() => {
      eventSource.close();
    });
  });

  return (
    <main style={{ "font-family": "system-ui, sans-serif", textAlign: "center", marginTop: "4rem" }}>
      <h1>Live Shared Counter</h1>
      <p>Real-time counter shared across every connected browser via SSE.</p>

      <div
        id="counter-value"
        style={{
          "font-size": "4rem",
          "font-variant-numeric": "tabular-nums",
          margin: "1rem 0",
        }}
      >
        {count.value}
      </div>

      <div style={{ display: "flex", gap: "0.5rem", "justify-content": "center" }}>
        <button
          onClick$={async () => {
            await fetch("/api/counter", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ delta: -1 }),
            });
          }}
        >
          − Decrement
        </button>
        <button
          onClick$={async () => {
            await fetch("/api/counter", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ delta: 1 }),
            });
          }}
        >
          + Increment
        </button>
      </div>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Live Shared Counter",
  meta: [
    {
      name: "description",
      content: "Real-time shared counter over Server-Sent Events",
    },
  ],
};

